files.content:
:host {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
}

.message-scroller {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 0;
}

.message-scroller__viewport {
  width: 100%;
  height: 100%;
  min-height: 0;
  overflow: auto;
  overscroll-behavior: contain;
  box-sizing: border-box;
}

.message-scroller__viewport:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-border-bold-brand);
  outline-offset: calc(-1 * var(--dimension-stroke-width-025));
}

.message-scroller__content {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-300);
  width: 100%;
  max-width: var(--dimension-panel-width-2xl);
  min-height: 100%;
  margin-inline: auto;
  padding-block-start: var(--dimension-space-200);
  padding-inline: var(--dimension-space-200);
  padding-block-end: calc(
    var(--dimension-space-200) + var(--ds-message-scroller-overlay-block-size, 0px)
  );
  box-sizing: border-box;
}

.message-scroller__overlay {
  position: absolute;
  right: 0;
  bottom: 0;
  left: 0;
  z-index: var(--dimension-z-index-floating);
}

.message-scroller__control {
  position: absolute;
  bottom: calc(
    var(--ds-message-scroller-overlay-content-block-size, 0px) + var(--dimension-space-200)
  );
  left: 50%;
  z-index: var(--dimension-z-index-floating);
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--dimension-radius-half);
  background: var(--color-background-transparent);
  box-shadow: var(--effect-elevation-elevated-md);
  transform: translateX(-50%);
  -webkit-backdrop-filter: blur(var(--effect-blur-sm));
  backdrop-filter: blur(var(--effect-blur-sm));
}

import {
  Component,
  Element,
  Event,
  EventEmitter,
  h,
  Host,
  Method,
  Prop,
  State,
} from '@stencil/core';
import type { MessageScrollerPosition } from '../conversation-types';

const LIVE_EDGE_THRESHOLD = 24;

@Component({
  tag: 'ds-message-scroller',
  styleUrl: 'MessageScroller.css',
  styleUrls: ['../../utils/scroll-edge-fade.css'],
  scoped: true,
})
export class MessageScroller {
  @Element() el!: HTMLElement;

  @Prop() busy: boolean = false;
  @Prop() autoFollow: boolean = true;
  @Prop() defaultPosition: MessageScrollerPosition = 'last-anchor';
  @Prop() messagesLabel: string = 'Messages';

  @Event() dsReachStart!: EventEmitter<void>;

  @State() private showScrollToLatest = false;

  private viewport?: HTMLElement;
  private content?: HTMLElement;
  private overlay?: HTMLElement;
  private resizeObserver?: ResizeObserver;
  private overlayResizeObserver?: ResizeObserver;
  private mutationObserver?: MutationObserver;
  private following = true;
  private atStart = false;
  private programmatic = false;
  private previousScrollHeight = 0;
  private overlayBlockSize = 0;
  private overlayContentBlockSize = 0;

  componentDidLoad() {
    this.connectObservers();
    requestAnimationFrame(() => this.applyDefaultPosition());
    document.addEventListener('selectionchange', this.handleSelectionChange);
  }

  disconnectedCallback() {
    this.resizeObserver?.disconnect();
    this.overlayResizeObserver?.disconnect();
    this.mutationObserver?.disconnect();
    document.removeEventListener('selectionchange', this.handleSelectionChange);
  }

  @Method()
  async scrollToMessage(id: string): Promise<boolean> {
    const message = Array.from(
      this.el.querySelectorAll<HTMLElement & { messageId?: string }>('ds-message')
    ).find(item => item.messageId === id || item.getAttribute('message-id') === id);
    if (!message) return false;
    this.following = false;
    this.showScrollToLatest = true;
    message.scrollIntoView({ block: 'start', behavior: this.motionBehavior() });
    return true;
  }

  @Method()
  async scrollToStart() {
    this.scrollTo(0);
    this.following = false;
    this.showScrollToLatest = Boolean(
      this.viewport && this.viewport.scrollHeight > this.viewport.clientHeight
    );
  }

  @Method()
  async scrollToEnd() {
    this.following = true;
    this.showScrollToLatest = false;
    this.scrollTo(this.viewport?.scrollHeight ?? 0);
  }

  private motionBehavior(): ScrollBehavior {
    return matchMedia('(prefers-reduced-motion: reduce)').matches ? 'auto' : 'smooth';
  }

  private scrollTo(top: number) {
    if (!this.viewport) return;
    this.programmatic = true;
    this.viewport.scrollTo({ top, behavior: this.motionBehavior() });
    requestAnimationFrame(() => {
      this.programmatic = false;
    });
  }

  private connectObservers() {
    if (!this.viewport || !this.content) return;
    this.previousScrollHeight = this.viewport.scrollHeight;
    this.resizeObserver = new ResizeObserver(() => this.handleContentGrowth());
    this.resizeObserver.observe(this.content);
    this.resizeObserver.observe(this.viewport);
    if (this.overlay) {
      this.overlayResizeObserver = new ResizeObserver(entries => {
        const blockSize = Math.ceil(entries[0]?.contentRect.height ?? 0);
        this.overlayBlockSize = blockSize;
        this.el.style.setProperty('--ds-message-scroller-overlay-block-size', `${blockSize}px`);
        this.syncOverlayContentBlockSize();
        this.handleContentGrowth();
      });
      this.overlayResizeObserver.observe(this.overlay);
    }
    this.mutationObserver = new MutationObserver(() => this.handleContentGrowth());
    this.mutationObserver.observe(this.content, {
      childList: true,
      subtree: true,
      characterData: true,
    });
  }

  private handleContentGrowth() {
    if (!this.viewport) return;
    const nextHeight = this.viewport.scrollHeight;
    const delta = nextHeight - this.previousScrollHeight;
    if (delta > 0 && this.viewport.scrollTop <= LIVE_EDGE_THRESHOLD && !this.following) {
      this.viewport.scrollTop += delta;
    } else if (this.autoFollow && this.following) {
      this.viewport.scrollTop = nextHeight;
    }
    this.previousScrollHeight = nextHeight;
    this.showScrollToLatest = !this.following && !this.isAtLiveEdge();
    this.syncContentFade();
  }

  private syncContentFade() {
    if (!this.viewport || !this.content) return;
    const fadeEnd = Math.max(this.viewport.scrollTop + this.viewport.clientHeight, 0);
    const fadeStart = Math.max(fadeEnd - this.overlayContentBlockSize, 0);
    this.content.style.setProperty('--ds-scroll-edge-fade-window-start', `${fadeStart}px`);
    this.content.style.setProperty('--ds-scroll-edge-fade-window-end', `${fadeEnd}px`);
  }

  private syncOverlayContentBlockSize() {
    if (!this.overlay) return;
    const assigned = this.el.querySelector<HTMLElement>('[slot="overlay"]');
    if (!(assigned instanceof HTMLElement)) {
      this.overlayContentBlockSize = this.overlayBlockSize;
    } else {
      const visibleContent =
        assigned.firstElementChild instanceof HTMLElement ? assigned.firstElementChild : assigned;
      const topInset = Math.max(
        Math.ceil(visibleContent.getBoundingClientRect().top - this.overlay.getBoundingClientRect().top),
        0
      );
      this.overlayContentBlockSize = Math.max(this.overlayBlockSize - topInset, 0);
    }
    this.el.style.setProperty(
      '--ds-message-scroller-overlay-content-block-size',
      `${this.overlayContentBlockSize}px`
    );
  }

  private applyDefaultPosition() {
    if (!this.viewport) return;
    if (this.defaultPosition === 'start') {
      this.viewport.scrollTop = 0;
      this.following = false;
      this.showScrollToLatest = this.viewport.scrollHeight > this.viewport.clientHeight;
      this.syncContentFade();
      return;
    }
    if (this.defaultPosition === 'last-anchor') {
      const anchors = this.el.querySelectorAll<HTMLElement>('ds-message[scroll-anchor]');
      const last = anchors.item(anchors.length - 1);
      if (last) {
        last.scrollIntoView({ block: 'start' });
        this.following = this.isAtLiveEdge();
        this.showScrollToLatest = !this.following;
        this.syncContentFade();
        return;
      }
    }
    this.viewport.scrollTop = this.viewport.scrollHeight;
    this.following = true;
    this.showScrollToLatest = false;
    this.syncContentFade();
  }

  private isAtLiveEdge(): boolean {
    if (!this.viewport) return true;
    return (
      this.viewport.scrollHeight - this.viewport.clientHeight - this.viewport.scrollTop <=
      LIVE_EDGE_THRESHOLD
    );
  }

  private handleScroll = () => {
    if (!this.viewport) return;
    this.syncContentFade();
    if (this.programmatic) return;
    this.following = this.isAtLiveEdge();
    this.showScrollToLatest = !this.following;
    const nextAtStart = this.viewport.scrollTop <= LIVE_EDGE_THRESHOLD;
    if (nextAtStart && !this.atStart) this.dsReachStart.emit();
    this.atStart = nextAtStart;
  };

  private releaseFollow = () => {
    this.following = false;
    this.showScrollToLatest = !this.isAtLiveEdge();
  };

  private handleSelectionChange = () => {
    const selection = document.getSelection();
    if (
      selection &&
      !selection.isCollapsed &&
      selection.anchorNode &&
      this.el.contains(selection.anchorNode)
    ) {
      this.following = false;
      this.showScrollToLatest = !this.isAtLiveEdge();
    }
  };

  render() {
    return (
      <Host>
        <div class="message-scroller">
          <div
            class="message-scroller__viewport"
            ref={element => {
              this.viewport = element;
            }}
            role="region"
            aria-label={this.messagesLabel}
            tabIndex={0}
            onScroll={this.handleScroll}
            onPointerDown={this.releaseFollow}
            onKeyDown={(event: KeyboardEvent) => {
              if (['ArrowUp', 'PageUp', 'Home'].includes(event.key)) this.releaseFollow();
            }}
          >
            <div
              class="message-scroller__content scroll-edge-fade--block-window"
              ref={element => {
                this.content = element;
              }}
              role="log"
              aria-live="polite"
              aria-relevant="additions"
              aria-busy={this.busy ? 'true' : undefined}
            >
              <slot />
            </div>
          </div>
          <div
            class="message-scroller__overlay"
            ref={element => {
              this.overlay = element;
            }}
          >
            <slot name="overlay" />
          </div>
          {this.showScrollToLatest ? (
            <div class="message-scroller__control">
              <ds-button-unfilled
                variant="icon"
                icon="ChevronDown"
                size="md"
                rounded
                hasBorder={false}
                aria-label="Scroll to latest message"
                onDsClick={() => void this.scrollToEnd()}
              />
            </div>
          ) : null}
        </div>
      </Host>
    );
  }
}
